import React from "react";

export default function AddNew({ setView }) {
  return (
    <div
      style={{
        display: "flex",
        justifyContent: "center",
        gap: "40px",
        paddingTop: "60px",
      }}
    >
      {/* TRAVEL CARD */}
      <div
        onClick={() => setView("travel")}
        style={{
          width: "260px",
          height: "180px",
          background: "#0f9d58",
          color: "white",
          borderRadius: "15px",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center",
          cursor: "pointer",
          fontSize: "22px",
          boxShadow: "0 4px 15px rgba(0,0,0,0.2)",
        }}
      >
        🚌 <br /> Travel Expense
      </div>

      {/* TICKET CARD */}
      <div
        onClick={() => setView("ticket")}
        style={{
          width: "260px",
          height: "180px",
          background: "#0078d4",
          color: "white",
          borderRadius: "15px",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center",
          cursor: "pointer",
          fontSize: "22px",
          boxShadow: "0 4px 15px rgba(0,0,0,0.2)",
        }}
      >
        🎫 <br /> Ticket Expense
      </div>
    </div>
  );
}
